SELECT d.*, COALESCE(c.comment_count, 0) as comment_count, COALESCE(col.collection_count, 0) as collection_count FROM documents d LEFT JOIN ( SELECT document_id, COUNT(*) as comment_count FROM comments GROUP BY document_id ) c ON d.id = c.document_id LEFT JOIN ( SELECT document_id, COUNT(*) as collection_count FROM document_collections GROUP BY document_id ) col ON d.id = col.document_id WHERE d.user_id = #{userId}
AND d.category = #{category}
AND d.tags LIKE CONCAT('%', #{tags}, '%')
AND (d.title LIKE CONCAT('%', #{keyword}, '%') OR d.content LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY d.updated_at DESC LIMIT #{offset}, #{size}

SELECT COUNT(*)
FROM documents d
WHERE d.user_id = #{userId}

    AND d.category = #{category}


    AND d.tags LIKE CONCAT('%', #{tags}, '%')


    AND (d.title LIKE CONCAT('%', #{keyword}, '%') OR d.content LIKE CONCAT('%', #{keyword}, '%'))

SELECT d.*, COALESCE(c.comment_count, 0) as comment_count, COALESCE(col.collection_count, 0) as collection_count FROM documents d LEFT JOIN ( SELECT document_id, COUNT(*) as comment_count FROM comments GROUP BY document_id ) c ON d.id = c.document_id LEFT JOIN ( SELECT document_id, COUNT(*) as collection_count FROM document_collections GROUP BY document_id ) col ON d.id = col.document_id WHERE d.permission != 'secret'
AND d.category = #{category}
AND (d.title LIKE CONCAT('%', #{keyword}, '%') OR d.content LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY d.updated_at DESC LIMIT #{offset}, #{size}

SELECT d.*, COALESCE(c.comment_count, 0) as comment_count, COALESCE(col.collection_count, 0) as collection_count FROM documents d LEFT JOIN ( SELECT document_id, COUNT(*) as comment_count FROM comments GROUP BY document_id ) c ON d.id = c.document_id LEFT JOIN ( SELECT document_id, COUNT(*) as collection_count FROM document_collections GROUP BY document_id ) col ON d.id = col.document_id WHERE d.permission = 'public'
AND d.category = #{category}
AND (d.title LIKE CONCAT('%', #{keyword}, '%') OR d.content LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY d.updated_at DESC LIMIT #{offset}, #{size}
